namespace Mocha;

/// <summary>
/// Defines the origin values reported for topology resources and links, indicating whether an item
/// was declared explicitly by the user or generated by the framework.
/// </summary>
public static class TopologyOrigin
{
    /// <summary>
    /// Identifies a topology item that was declared explicitly through a user descriptor call.
    /// </summary>
    public const string Declared = "declared";

    /// <summary>
    /// Identifies a topology item generated by framework conventions or routing infrastructure.
    /// </summary>
    public const string Convention = "convention";

    /// <summary>
    /// Identifies a topology item owned by a receive endpoint.
    /// </summary>
    public const string Endpoint = "endpoint";

    internal static string Normalize(string? origin)
        => origin ?? Convention;
}
